import json
from collections import defaultdict

# Load business data
businesses = json.load(open(var_call_4gD7RcgzO0LTD6TtHVlV0ELM, 'r'))
review_aggs = var_call_VdiePHeCmvkzPqtOE7ClQitB

# build review map
rev_map = {}
for r in review_aggs:
    br = r.get('business_ref')
    try:
        avg = float(r.get('avg_rating'))
    except:
        avg = None
    try:
        cnt = int(r.get('review_count'))
    except:
        cnt = 0
    rev_map[br] = (avg, cnt)

# helper to check credit acceptance
def accepts_credit(attributes):
    if not attributes:
        return False
    if isinstance(attributes, dict):
        val = attributes.get('BusinessAcceptsCreditCards')
        if isinstance(val, bool):
            return val
        if isinstance(val, str) and val.lower().strip() == 'true':
            return True
        return False
    s = str(attributes).lower()
    return 'businessacceptscreditcards' in s and 'true' in s

# helper to extract categories from description
def extract_categories(description):
    if not description:
        return []
    desc = description
    # try to get substring after last ' in '
    idx = desc.lower().rfind(' in ')
    if idx != -1:
        tail = desc[idx+4:]
    else:
        # fallback after 'including'
        idx2 = desc.lower().find('including')
        if idx2 != -1:
            tail = desc[idx2+9:]
        else:
            tail = desc
    tail = tail.strip()
    # remove trailing sentence parts after '.'
    if '.' in tail:
        tail = tail.split('.')[0]
    # replace '&' and ' and ' with commas
    tail = tail.replace('&', ',')
    tail = tail.replace(' and ', ',')
    parts = [p.strip().strip("'\"") for p in tail.split(',') if p.strip()]
    # filter out parts that are too long
    parts = [p.lower() for p in parts if len(p.split()) <= 6]
    return parts

# build mapping
cat_counts = defaultdict(int)
cat_businesses = defaultdict(list)
for b in businesses:
    bid = b.get('business_id')
    attrs = b.get('attributes')
    desc = b.get('description')
    if accepts_credit(attrs):
        cats = extract_categories(desc)
        if not cats:
            continue
        for c in cats:
            cat_counts[c] += 1
            cat_businesses[c].append(bid)

if not cat_counts:
    result = {'category': None, 'business_count': 0, 'average_rating': None}
else:
    # choose category with max count
    max_cat = max(cat_counts.items(), key=lambda x: (x[1], x[0]))[0]
    max_count = cat_counts[max_cat]
    bids = cat_businesses[max_cat]
    total_reviews = 0
    weighted_sum = 0.0
    avg_list = []
    for bid in bids:
        bref = bid.replace('businessid_', 'businessref_')
        if bref in rev_map:
            avg, cnt = rev_map[bref]
            if avg is not None and cnt>0:
                weighted_sum += avg * cnt
                total_reviews += cnt
                avg_list.append(avg)
    if total_reviews > 0:
        final_avg = weighted_sum / total_reviews
    elif avg_list:
        final_avg = sum(avg_list) / len(avg_list)
    else:
        final_avg = None
    result = {'category': max_cat, 'business_count': max_count, 'average_rating': (None if final_avg is None else float(final_avg))}

import json
out = json.dumps(result)
print("__RESULT__:")
print(out)

